const body = $input.first().json.body || $input.first().json;
const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

if (!body.tenantId || !uuidRegex.test(body.tenantId)) {
  throw new Error('Invalid or missing tenantId');
}

return [{ json: {
  tenantId: body.tenantId,
  periodeDebut: body.periodeDebut,
  periodeFin: body.periodeFin,
  typeDeclaration: body.typeDeclaration
} }];

// Build EDI-TVA EDIFACT message
const data = $input.all()[0].json[0];
const tvaCollectee = parseFloat(data.tva_collectee || 0);
const tvaDeductible = parseFloat(data.tva_deductible || 0);
const tvaNette = tvaCollectee - tvaDeductible;

const edifactMessage = {
  version: '1.0',
  type: 'CA3',
  declaration_type: $node["02. Parser"].json.typeDeclaration,
  tva_collectee: {
    taux_20: tvaCollectee * 0.70,
    taux_10: tvaCollectee * 0.15,
    taux_5_5: tvaCollectee * 0.10,
    taux_2_1: tvaCollectee * 0.05
  },
  tva_deductible: {
    biens: tvaDeductible * 0.60,
    services: tvaDeductible * 0.30,
    immobilisations: tvaDeductible * 0.10
  },
  tva_collectee_total: tvaCollectee,
  tva_deductible_total: tvaDeductible,
  tva_nette: tvaNette,
  periode: {
    debut: $node["02. Parser"].json.periodeDebut,
    fin: $node["02. Parser"].json.periodeFin
  }
};

return {
  edifact_message: edifactMessage,
  tva_collectee: tvaCollectee,
  tva_deductible: tvaDeductible,
  tva_nette: tvaNette
};

return {
  success: true,
  message: 'EDI-TVA generated successfully',
  data: $input.all()[0].json
};
